class Solution {
public:
    string maximumBinaryString(string binary) {
        int zeros = 0, ones = 0;
        for (char c : binary) {
            if (c == '0') zeros++;
            else ones++;
        }
        if (zeros > 1) {
            binary[0] = '1';
            for (int i = 1; i < zeros - 1; i++) binary[i] = '0';
            for (int i = zeros - 1; i < binary.size(); i++) binary[i] = '1';
        }
        return binary;
    }
};
